 (SELECT id FROM topics WHERE slug='recurrence-relations' LIMIT 1),
 'gate-cse',false,NULL,'MCQ','medium',2,
 'Identify the asymptotic time complexity for the recurrence $T(n) = T(n-1) + n$, assuming $T(1) = 1$.',
