    'Boolean algebra, K-maps, combinational & sequential circuits, and number representations.',
    '#10b981', '#059669', 'cpu' -- emerald
  )
  ON CONFLICT (slug) DO UPDATE
    SET title = EXCLUDED.title, description = EXCLUDED.description
  RETURNING id INTO subj_id;

  -- 2. Chapters
  INSERT INTO chapters (subject_id, name, slug, order_index) VALUES (subj_id, 'Boolean Algebra & Logic Gates', 'boolean-logic', 1) RETURNING id INTO ch1_id;
  INSERT INTO chapters (subject_id, name, slug, order_index) VALUES (subj_id, 'Combinational Circuits', 'combinational', 2) RETURNING id INTO ch2_id;
  INSERT INTO chapters (subject_id, name, slug, order_index) VALUES (subj_id, 'Sequential Circuits & Counters', 'sequential', 3) RETURNING id INTO ch3_id;
  INSERT INTO chapters (subject_id, name, slug, order_index) VALUES (subj_id, 'Number Systems & Converters', 'numbers-converters', 4) RETURNING id INTO ch4_id;

  -- 3. Topics
  -- Chapter 1: Boolean Algebra & Logic Gates
  INSERT INTO topics (chapter_id, slug, name, order_index) VALUES (ch1_id, 'logic-gates',     'Basic & Universal Logic Gates',     1) ON CONFLICT DO NOTHING;
  INSERT INTO topics (chapter_id, slug, name, order_index) VALUES (ch1_id, 'boolean-laws',    'Boolean Laws & Theorems',           2) ON CONFLICT DO NOTHING;
  INSERT INTO topics (chapter_id, slug, name, order_index) VALUES (ch1_id, 'k-maps',          'Karnaugh Maps & Minimization',      3) ON CONFLICT DO NOTHING;

  -- Chapter 2: Combinational Circuits
