  INSERT INTO topics (chapter_id, slug, name, order_index) VALUES (ch2_id, 'multiplexers',    'Multiplexers & Demultiplexers',     2) ON CONFLICT DO NOTHING;
  INSERT INTO topics (chapter_id, slug, name, order_index) VALUES (ch2_id, 'decoders',        'Decoders & Encoders',               3) ON CONFLICT DO NOTHING;
  INSERT INTO topics (chapter_id, slug, name, order_index) VALUES (ch2_id, 'circuit-delay',   'Combinational Circuit Delays',      4) ON CONFLICT DO NOTHING;

  -- Chapter 3: Sequential Circuits & Counters
  INSERT INTO topics (chapter_id, slug, name, order_index) VALUES (ch3_id, 'flip-flops',      'Latches & Flip-Flops',              1) ON CONFLICT DO NOTHING;
  INSERT INTO topics (chapter_id, slug, name, order_index) VALUES (ch3_id, 'state-machines',  'Finite State Machines (Mealy/Moore)',2) ON CONFLICT DO NOTHING;
  INSERT INTO topics (chapter_id, slug, name, order_index) VALUES (ch3_id, 'counters',        'Synchronous & Asynchronous Counters',3) ON CONFLICT DO NOTHING;
  INSERT INTO topics (chapter_id, slug, name, order_index) VALUES (ch3_id, 'registers',       'Shift Registers',                   4) ON CONFLICT DO NOTHING;

  -- Chapter 4: Number Systems & Converters
  INSERT INTO topics (chapter_id, slug, name, order_index) VALUES (ch4_id, 'number-systems',  'Base Conversions & Number Systems', 1) ON CONFLICT DO NOTHING;
  INSERT INTO topics (chapter_id, slug, name, order_index) VALUES (ch4_id, 'signed-numbers',  'Signed Numbers & 2s Complement',    2) ON CONFLICT DO NOTHING;
  INSERT INTO topics (chapter_id, slug, name, order_index) VALUES (ch4_id, 'adc-dac',         'ADC & DAC Converters',              3) ON CONFLICT DO NOTHING;

  -- 4. Tags
  INSERT INTO tags (name, slug) VALUES ('Boolean Algebra', 'boolean-algebra') ON CONFLICT DO NOTHING;
  INSERT INTO tags (name, slug) VALUES ('K-Map',           'k-map')           ON CONFLICT DO NOTHING;
  INSERT INTO tags (name, slug) VALUES ('Multiplexer',     'multiplexer')     ON CONFLICT DO NOTHING;
  INSERT INTO tags (name, slug) VALUES ('Flip-Flop',       'flip-flop')       ON CONFLICT DO NOTHING;
  INSERT INTO tags (name, slug) VALUES ('Counter',         'counter')         ON CONFLICT DO NOTHING;
  INSERT INTO tags (name, slug) VALUES ('State Machine',   'state-machine')   ON CONFLICT DO NOTHING;
  INSERT INTO tags (name, slug) VALUES ('Delay',           'dl-delay')        ON CONFLICT DO NOTHING;
  INSERT INTO tags (name, slug) VALUES ('Number System',   'number-system')   ON CONFLICT DO NOTHING;

END $$;

